exercise.solutionCode:
const scores = [55, 82, 90, 45, 73, 88, 38, 91];

const passing = scores.filter(s => s >= 60);
console.log(`Passing: ${passing.length} students`);

const boosted = passing.map(s => s + 5);

boosted.forEach(s => process.stdout.write(s + " "));
console.log();
